  "options": [],
  "questionProse": [
    "HTML में `<time>` एलिमेंट का उपयोग कैसे किया जाता है?"
  ],
  "explanationProse": [
    "`<time>` एलिमेंट का उपयोग तारीखों, समय या अवधि को मार्कअप करने के लिए किया जाता है। यह इंसानों के लिए पढ़ने योग्य कंटेंट और मशीनों के लिए पार्स करने योग्य `datetime` एट्रिब्यूट को एक साथ रखता है। ध्यान रहे, HTML में कोई `<date>` एलिमेंट मौजूद ही नहीं है।"
  ]
}
